import java.lang.reflect.*;

public class ReflectionDemo {

    static class Calculator {
        private double result = 0;
        public double add(double a, double b)    { return a + b; }
        public double multiply(double a, double b){ return a * b; }
        private double secretFormula(double x)   { return x * x + 2 * x + 1; }
        public double getResult() { return result; }
    }

    public static void main(String[] args) throws Exception {
        // ── Inspect class ────────────────────────────────────
        Class<?> clz = Calculator.class;
        System.out.println("Class: " + clz.getName());
        System.out.println("\nPublic methods:");
        for (Method m : clz.getMethods())
            if (m.getDeclaringClass() == clz)
                System.out.println("  " + m.getName() + " → " + m.getReturnType().getSimpleName());

        // ── Invoke public method dynamically ──────────────────
        Calculator calc = new Calculator();
        Method addMethod = clz.getMethod("add", double.class, double.class);
        double sum = (double) addMethod.invoke(calc, 3.5, 2.5);
        System.out.println("\n3.5 + 2.5 = " + sum);

        // ── Access private method ─────────────────────────────
        Method secret = clz.getDeclaredMethod("secretFormula", double.class);
        secret.setAccessible(true); // bypass private
        double result = (double) secret.invoke(calc, 4.0); // 4²+2*4+1 = 25
        System.out.println("secretFormula(4) = " + result);

        // ── Access private field ──────────────────────────────
        Field resultField = clz.getDeclaredField("result");
        resultField.setAccessible(true);
        resultField.set(calc, 99.0);
        System.out.println("Injected result: " + calc.getResult());

        // ── Dynamic instantiation ─────────────────────────────
        Calculator calc2 = (Calculator) clz.getDeclaredConstructor().newInstance();
        System.out.println("New instance via reflection: " + calc2.add(1,2));
    }
}

import java.lang.annotation.*;
import java.lang.reflect.*;
import java.util.*;

public class AnnotationFramework {

    // ── Define custom annotations ─────────────────────────────
    @Retention(RetentionPolicy.RUNTIME)
    @Target(ElementType.FIELD)
    @interface NotNull { String message() default "must not be null"; }

    @Retention(RetentionPolicy.RUNTIME)
    @Target(ElementType.FIELD)
    @interface Min { int value(); String message() default "too small"; }

    @Retention(RetentionPolicy.RUNTIME)
    @Target(ElementType.FIELD)
    @interface MaxLength { int value(); String message() default "too long"; }

    // ── Model with annotations ────────────────────────────────
    static class User {
        @NotNull String name;
        @Min(18) int age;
        @MaxLength(50) @NotNull String email;

        User(String name, int age, String email) {
            this.name = name; this.age = age; this.email = email;
        }
    }

    // ── Validator using reflection ────────────────────────────
    static List<String> validate(Object obj) throws IllegalAccessException {
        List<String> errors = new ArrayList<>();
        for (Field field : obj.getClass().getDeclaredFields()) {
            field.setAccessible(true);
            Object value = field.get(obj);

            if (field.isAnnotationPresent(NotNull.class) && value == null)
                errors.add(field.getName() + ": " + field.getAnnotation(NotNull.class).message());

            if (field.isAnnotationPresent(Min.class) && value instanceof Integer i) {
                int min = field.getAnnotation(Min.class).value();
                if (i < min) errors.add(field.getName() + ": must be >= " + min);
            }

            if (field.isAnnotationPresent(MaxLength.class) && value instanceof String s) {
                int max = field.getAnnotation(MaxLength.class).value();
                if (s.length() > max) errors.add(field.getName() + ": length > " + max);
            }
        }
        return errors;
    }

    public static void main(String[] args) throws Exception {
        User valid   = new User("Alice", 25, "alice@example.com");
        User invalid = new User(null, 15, "a".repeat(60));

        System.out.println("Valid:   " + validate(valid));
        System.out.println("Invalid: " + validate(invalid));
    }
}

