import java.lang.reflect.*;
import java.util.*;

public class Q1 {
    static class LegacyService {
        @Deprecated public void oldMethod() {}
        public void newMethod() {}
        @Deprecated public void anotherOld() {}
    }

    public static List<String> findDeprecatedMethods(Class<?> clz) {
        List<String> result = new ArrayList<>();
        for (Method m : clz.getDeclaredMethods())
            if (m.isAnnotationPresent(Deprecated.class))
                result.add(m.getName());
        return result;
    }

    public static void main(String[] args) {
        System.out.println(findDeprecatedMethods(LegacyService.class));
    }
}

