import java.lang.reflect.*;
import java.util.*;

public class Q2 {
    static class Product { String name; int price; boolean available;
        Product(String n, int p, boolean a) { name=n; price=p; available=a; } }

    public static String toJson(Object obj) throws IllegalAccessException {
        StringBuilder sb = new StringBuilder("{");
        Field[] fields = obj.getClass().getDeclaredFields();
        for (int i = 0; i < fields.length; i++) {
            fields[i].setAccessible(true);
            sb.append('"').append(fields[i].getName()).append('"').append(':');
            Object val = fields[i].get(obj);
            if (val instanceof String) sb.append('"').append(val).append('"');
            else sb.append(val);
            if (i < fields.length - 1) sb.append(',');
        }
        return sb.append('}').toString();
    }
    public static void main(String[] args) throws Exception {
        System.out.println(toJson(new Product("Laptop", 999, true)));
    }
}

