import java.lang.annotation.*;
import java.lang.reflect.*;

public class Q3 {
    @Retention(RetentionPolicy.RUNTIME)
    @Target(ElementType.METHOD)
    @interface Log {}

    static class Service {
        @Log
        public String process(String input) throws InterruptedException {
            Thread.sleep(50); return input.toUpperCase();
        }
        public String skip(String input) { return input; }
    }

    public static Object timedInvoke(Object target, String methodName, Object... args) throws Exception {
        Method method = target.getClass().getMethod(methodName, String.class);
        if (method.isAnnotationPresent(Log.class)) {
            long start = System.currentTimeMillis();
            Object result = method.invoke(target, args);
            System.out.println("[" + methodName + "] executed in " + (System.currentTimeMillis()-start) + "ms → " + result);
            return result;
        }
        return method.invoke(target, args);
    }

    public static void main(String[] args) throws Exception {
        Service svc = new Service();
        timedInvoke(svc, "process", "hello"); // [process] executed in ~50ms → HELLO
        timedInvoke(svc, "skip",    "world"); // no log
    }
}
